example.code:
// Preferred: role and text selectors
await page.click('role=button[name="Submit"]');
await page.click('text=Sign in');

// Acceptable: stable semantic CSS
await page.click('button[type="submit"]');

// Avoid: Tailwind utility class selectors
// await page.click('.bg-blue-600');  -- breaks on every refactor

// Playwright auto-waits for element to be actionable
await page.click('#button');      // waits for element, enabled, stable
await page.fill('#input', 'text'); // waits for editable

// Explicit condition wait when needed
await page.waitForSelector('#dynamic-element');
await page.waitForLoadState('networkidle');
await page.waitForURL('**/dashboard');

// Save auth state once
await context.storageState({ path: 'auth.json' });

// Reuse in subsequent runs
const context = await browser.newContext({ storageState: 'auth.json' });

await page.route('**/*.{png,jpg,jpeg,svg,woff2,gif}', route => route.abort());
await page.route('**/(analytics|gtm|hotjar)**', route => route.abort());

// Mock API for isolated testing
await page.route('**/api/users', route => {
  route.fulfill({ status: 200, contentType: 'application/json',
    body: JSON.stringify([{ id: 1, name: 'Test User' }]) });
});
